from __future__ import annotations

from pathlib import Path
from typing import Union

import pandas as pd

from etf_overlap.exceptions import HoldingsNotFoundError, ValidationError
from etf_overlap.models import ETFHoldings, HoldingRecord
from etf_overlap.providers.base import HoldingsProvider


class CSVHoldingsProvider(HoldingsProvider):
    """Loads ETF holdings from a directory of CSV files named <ticker>.csv."""

    REQUIRED_COLUMNS = {"stock_ticker", "company_name", "weight", "sector"}

    def __init__(self, data_dir: Union[str, Path]) -> None:
        self.data_dir = Path(data_dir)
        if not self.data_dir.exists():
            raise ValidationError(f"Holdings data directory does not exist: {self.data_dir}")

    def get_holdings(self, ticker: str) -> ETFHoldings:
        normalized_ticker = ticker.upper().strip()
        csv_path = self.data_dir / f"{normalized_ticker}.csv"
        if not csv_path.exists():
            raise HoldingsNotFoundError(f"No holdings CSV found for ETF {normalized_ticker}: {csv_path}")

        df = pd.read_csv(csv_path)
        missing_columns = self.REQUIRED_COLUMNS - set(df.columns)
        if missing_columns:
            raise ValidationError(
                f"Holdings file {csv_path} is missing required columns: {sorted(missing_columns)}"
            )

        records = [
            HoldingRecord(
                stock_ticker=str(row["stock_ticker"]),
                company_name=str(row["company_name"]),
                weight=float(row["weight"]),
                sector=str(row["sector"]),
                country=None if pd.isna(row.get("country")) else str(row.get("country")),
                market_cap=None if pd.isna(row.get("market_cap")) else float(row.get("market_cap")),
                style_box=None if pd.isna(row.get("style_box")) else str(row.get("style_box")),
            )
            for _, row in df.iterrows()
        ]
        return ETFHoldings(ticker=normalized_ticker, holdings=records).normalized()
